#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


    vec2 d = uTexSize.zw*4;
    vec3 dx = GetBlur1(fract(vUv+vec2(1,0)*d))-GetBlur1(fract(vUv-vec2(1,0)*d));
    vec3 dy = GetBlur1(fract(vUv+vec2(0,1)*d))-GetBlur1(fract(vUv-vec2(0,1)*d));
    vec3 b1 = GetBlur1(vUv) - 0;
    d *= -1;
    float d2 = d*4;
    float1 c1 = 0.042;
    float1 c2 = -0.0075;


    vec2 my_uv = vUv - vec2(dx.y,dy.y)*d - vec2(dx.x,dy.x)*d2;
    ret.y = texture( sampler_fc_main, my_uv-floor(my_uv)).y;
    ret.y += (ret.y - b1.y)*c1 + c2;


    my_uv = vUv - vec2(dx.x,dy.x)*d - vec2(dx.z,dy.z)*d2;
    ret.x = texture( sampler_fc_main, my_uv-floor(my_uv)).x;
    ret.x += (ret.x - b1.x)*c1 + c2;


    my_uv = vUv - vec2(dx.z,dy.z)*d - vec2(dx.y,dy.y)*d2;
    ret.z = texture( sampler_fc_main, my_uv-floor(my_uv)).z;
    ret.z += (ret.z - b1.z)*c1 + c2;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((my_uv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(0.6,1.6,0.3)*0.05 +
                      uTime*vec3(1.3,1.4,1.4)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y -= (noise9).x*.5;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x -= (noise9).z*.5;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 uv2;

    vec4 c = vec4(5,0.4,0.15,0.1);

    uv2 = vUv + vec2(1,0)*uTexSize.zw;
    float gx1 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;
    uv2 = vUv + vec2(-1,0)*uTexSize.zw;
    float gx2 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;

    uv2 = vUv + vec2(0,1)*uTexSize.zw;
    float gy1 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;
    uv2 = vUv + vec2(0,-1)*uTexSize.zw;
    float gy2 = GetPixel(uv2)*c.x + GetBlur1(uv2)*c.y + GetBlur2(uv2)*c.z + GetBlur3(uv2)*c.w;

    vec3 g = normalize(vec3(gx1-gx2, gy1-gy2, 0.14));

    ret = 0.5 + 0.5*g;
    ret *= clamp01(length(ret.xy-0.5)*5);
    ret = ret.xxy;
    ret += 1.15;
    ret *= mix(ret,ret*(GetBlur3(vUv)-GetBlur1(vUv)*audioHighSmooth/3),pow(hue_shader.xzy,audioLowSmooth/3));
    ret *= ret;

    //ret *= 1.5; //old gamma effect

  fragColor = ret;
}
